import{_ as n,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Invalid Grant-Fehlerbehebung: Kontosperrungswiederherstellung | Antigravity-Manager","description":"Lernen Sie die Bedeutung des invalid_grant-Fehlers und die automatische Verarbeitungslogik. Bestätigen Sie die Unwirksamkeit des refresh_token, lösen Sie durch erneutes OAuth-Hinzufügen des Kontos die automatische Entsperrung aus und verifizieren Sie, dass die Wiederherstellung für den Proxy wirksam ist.","frontmatter":{"title":"Invalid Grant-Fehlerbehebung: Kontosperrungswiederherstellung | Antigravity-Manager","sidebarTitle":"Wie man einen gesperrten Konto wiederherstellt","subtitle":"invalid_grant und automatische Kontosperrung: Warum es passiert und wie man wiederherstellt","description":"Lernen Sie die Bedeutung des invalid_grant-Fehlers und die automatische Verarbeitungslogik. Bestätigen Sie die Unwirksamkeit des refresh_token, lösen Sie durch erneutes OAuth-Hinzufügen des Kontos die automatische Entsperrung aus und verifizieren Sie, dass die Wiederherstellung für den Proxy wirksam ist.","tags":["FAQ","Fehlerbehebung","OAuth","Kontoverwaltung","invalid_grant"],"prerequisite":["start-add-account","start-first-run-data","advanced-scheduling"],"order":1},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md","filePath":"de/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"}'),a={name:"de/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"};function s(d,e,o,l,u,h){return r(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="invalid-grant-und-automatische-kontosperrung-warum-es-passiert-und-wie-man-wiederherstellt" tabindex="-1">invalid_grant und automatische Kontosperrung: Warum es passiert und wie man wiederherstellt <a class="header-anchor" href="#invalid-grant-und-automatische-kontosperrung-warum-es-passiert-und-wie-man-wiederherstellt" aria-label="Permalink to &quot;invalid_grant und automatische Kontosperrung: Warum es passiert und wie man wiederherstellt&quot;">​</a></h1><h2 id="was-sie-nach-diesem-lernen-konnen" tabindex="-1">Was Sie nach diesem Lernen können <a class="header-anchor" href="#was-sie-nach-diesem-lernen-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Lernen können&quot;">​</a></h2><ul><li>Wenn Sie <code>invalid_grant</code> sehen, wissen Sie, zu welcher Art von refresh_token-Problem es gehört</li><li>Verstehen Sie, warum ein Konto plötzlich nicht mehr verfügbar ist: Unter welchen Umständen wird es automatisch gesperrt und wie das System nach der Sperrung damit umgeht</li><li>Setzen Sie das Konto auf dem kürzesten Weg wiederher und bestätigen Sie, dass die Wiederherstellung für den laufenden Proxy wirksam ist</li></ul><h2 id="ihre-symptome" tabindex="-1">Ihre Symptome <a class="header-anchor" href="#ihre-symptome" aria-label="Permalink to &quot;Ihre Symptome&quot;">​</a></h2><ul><li>Plötzliches Auftreten von Fehlern beim Aufrufen des lokalen Proxy mit der Fehlermeldung <code>invalid_grant</code></li><li>Das Konto ist immer noch in der Accounts-Liste vorhanden, aber der Proxy überspringt es immer (oder Sie haben das Gefühl, dass es &quot;nie mehr verwendet wird&quot;)</li><li>Wenn Sie nur wenige Konten haben, verschlechtert sich die allgemeine Verfügbarkeit deutlich nach einmaligem Auftreten von <code>invalid_grant</code></li></ul><h2 id="was-ist-invalid-grant" tabindex="-1">Was ist invalid_grant? <a class="header-anchor" href="#was-ist-invalid-grant" aria-label="Permalink to &quot;Was ist invalid_grant?&quot;">​</a></h2><p><strong>invalid_grant</strong> ist ein Fehler, den Google OAuth beim Aktualisieren des <code>access_token</code> zurückgibt. Für Antigravity Tools bedeutet dies, dass der <code>refresh_token</code> eines Kontos wahrscheinlich widerrufen oder abgelaufen ist. Das weitere Wiederholen führt nur zu wiederholten Fehlschlägen, daher markiert das System das Konto als nicht verfügbar und entfernt es aus dem Proxy-Pool.</p><h2 id="grundidee-das-system-uberspringt-nicht-temporar-sondern-sperrt-dauerhaft" tabindex="-1">Grundidee: Das System &quot;überspringt nicht temporär&quot;, sondern &quot;sperrt dauerhaft&quot; <a class="header-anchor" href="#grundidee-das-system-uberspringt-nicht-temporar-sondern-sperrt-dauerhaft" aria-label="Permalink to &quot;Grundidee: Das System &quot;überspringt nicht temporär&quot;, sondern &quot;sperrt dauerhaft&quot;&quot;">​</a></h2><p>Wenn der Proxy erkennt, dass die Fehlerzeichenfolge beim Aktualisieren des Token <code>invalid_grant</code> enthält, werden zwei Schritte ausgeführt:</p><ol><li><strong>Das Konto als disabled markieren</strong> (persistieren in der Konto-JSON-Datei)</li><li><strong>Das Konto aus dem in-Memory Token-Pool entfernen</strong> (um zu vermeiden, dass wiederholt derselbe fehlerhafte Konto ausgewählt wird)</li></ol><p>Dies ist der Grund, warum Sie sehen: &quot;Das Konto ist noch da, aber der Proxy verwendet es nicht mehr.&quot;</p><div class="info custom-block"><p class="custom-block-title">disabled vs proxy_disabled</p><ul><li><code>disabled=true</code>: Das Konto ist &quot;dauerhaft gesperrt&quot; (der typische Grund ist <code>invalid_grant</code>). Beim Laden des Konto-Pools wird es direkt übersprungen.</li><li><code>proxy_disabled=true</code>: Das Konto ist nur &quot;für den Proxy nicht verfügbar&quot; (manuelle Sperrung/Batch-Operationen/Kontingentschutz-bezogene Logik), die Semantik ist anders.</li></ul><p>Diese beiden Zustände werden beim Laden des Konto-Pools separat beurteilt: Zuerst wird <code>disabled</code> beurteilt, dann werden Kontingentschutz und <code>proxy_disabled</code> beurteilt.</p></div><h2 id="schritt-fur-schritt" tabindex="-1">Schritt-für-Schritt <a class="header-anchor" href="#schritt-fur-schritt" aria-label="Permalink to &quot;Schritt-für-Schritt&quot;">​</a></h2><h3 id="schritt-1-bestatigen-sie-ob-invalid-grant-durch-refresh-token-aktualisierung-ausgelost-wurde" tabindex="-1">Schritt 1: Bestätigen Sie, ob invalid_grant durch refresh_token-Aktualisierung ausgelöst wurde <a class="header-anchor" href="#schritt-1-bestatigen-sie-ob-invalid-grant-durch-refresh-token-aktualisierung-ausgelost-wurde" aria-label="Permalink to &quot;Schritt 1: Bestätigen Sie, ob invalid_grant durch refresh_token-Aktualisierung ausgelöst wurde&quot;">​</a></h3><p><strong>Warum</strong>: <code>invalid_grant</code> kann in mehreren Aufrufketten auftreten, aber die &quot;automatische Sperrung&quot; dieses Projekts wird nur ausgelöst, wenn das <strong>Aktualisieren des access_token fehlschlägt</strong>.</p><p>In den Proxy-Protokollen sehen Sie ähnliche Fehlerprotokolle (Schlüsselwörter sind <code>Token 刷新失败</code> + <code>invalid_grant</code>):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Token 刷新失败 (&lt;email&gt;): &lt;...invalid_grant...&gt;，尝试下一个账号</span></span>
<span class="line"><span>Disabling account due to invalid_grant (&lt;email&gt;): refresh_token likely revoked/expired</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Nachdem <code>invalid_grant</code> bei demselben Konto aufgetreten ist, wird es sehr schnell nicht mehr ausgewählt (weil es aus dem Token-Pool entfernt wurde).</p><h3 id="schritt-2-uberprufen-sie-das-disabled-feld-in-der-kontodatei-optional-aber-am-genauesten" tabindex="-1">Schritt 2: Überprüfen Sie das disabled-Feld in der Kontodatei (optional, aber am genauesten) <a class="header-anchor" href="#schritt-2-uberprufen-sie-das-disabled-feld-in-der-kontodatei-optional-aber-am-genauesten" aria-label="Permalink to &quot;Schritt 2: Überprüfen Sie das disabled-Feld in der Kontodatei (optional, aber am genauesten)&quot;">​</a></h3><p><strong>Warum</strong>: Die automatische Sperrung wird &quot;persistiert&quot;, daher können Sie nach Bestätigung des Dateiinhalts den Fehlschluss &quot;es ist nur eine temporäre Rotation&quot; ausschließen.</p><p>Die Kontodatei befindet sich im <code>accounts/</code>-Verzeichnis des Anwendungsdatenverzeichnisses (für den Speicherort des Datenverzeichnisses siehe <strong><a href="./../../start/first-run-data/">Erster Start: Datenverzeichnis, Protokolle, Taskleiste und automatischer Start</a></strong>). Wenn das Konto gesperrt ist, erscheinen diese drei Felder in der Datei:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;invalid_grant: ...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: <code>disabled</code> ist <code>true</code>, und <code>disabled_reason</code> enthält das Präfix <code>invalid_grant:</code>.</p><h3 id="schritt-3-wiederherstellen-des-kontos-empfohlene-methode-dasselbe-konto-erneut-hinzufugen" tabindex="-1">Schritt 3: Wiederherstellen des Kontos (empfohlene Methode: dasselbe Konto erneut hinzufügen) <a class="header-anchor" href="#schritt-3-wiederherstellen-des-kontos-empfohlene-methode-dasselbe-konto-erneut-hinzufugen" aria-label="Permalink to &quot;Schritt 3: Wiederherstellen des Kontos (empfohlene Methode: dasselbe Konto erneut hinzufügen)&quot;">​</a></h3><p><strong>Warum</strong>: Die &quot;Wiederherstellung&quot; dieses Projekts besteht nicht darin, einen Schalter manuell im Proxy zu drücken, sondern die automatische Entsperrung durch &quot;explizites Aktualisieren des Token&quot; auszulösen.</p><p>Gehen Sie zur <strong>Accounts</strong>-Seite und fügen Sie das Konto mit Ihren neuen Anmeldeinformationen erneut hinzu (wählen Sie eine der beiden Methoden):</p><ol><li>Durchlaufen Sie erneut den OAuth-Autorisierungsablauf (siehe <strong><a href="./../../start/add-account/">Konto hinzufügen: OAuth/Refresh Token Dualkanal und Best Practices</a></strong>)</li><li>Fügen Sie das Konto erneut mit einem neuen <code>refresh_token</code> hinzu (das System führt ein Upsert basierend auf der von Google zurückgegebenen E-Mail-Adresse durch)</li></ol><p>Wenn das System erkennt, dass das <code>refresh_token</code> oder <code>access_token</code> dieses Upserts vom alten Wert abweicht und das Konto zuvor <code>disabled=true</code> war, werden automatisch folgende Felder gelöscht:</p><ul><li><code>disabled</code></li><li><code>disabled_reason</code></li><li><code>disabled_at</code></li></ul><p><strong>Was Sie sehen sollten</strong>: Das Konto befindet sich nicht mehr im disabled-Zustand, und (wenn der Proxy läuft) wird der Konto-Pool automatisch neu geladen, damit die Wiederherstellung sofort wirksam wird.</p><h3 id="schritt-4-uberprufen-sie-ob-die-wiederherstellung-fur-den-proxy-wirksam-ist" tabindex="-1">Schritt 4: Überprüfen Sie, ob die Wiederherstellung für den Proxy wirksam ist <a class="header-anchor" href="#schritt-4-uberprufen-sie-ob-die-wiederherstellung-fur-den-proxy-wirksam-ist" aria-label="Permalink to &quot;Schritt 4: Überprüfen Sie, ob die Wiederherstellung für den Proxy wirksam ist&quot;">​</a></h3><p><strong>Warum</strong>: Wenn Sie nur ein Konto haben oder andere Konten auch nicht verfügbar sind, sollten Sie sofort sehen, dass &quot;die Verfügbarkeit zurückgekehrt ist&quot;, nachdem Sie wiederhergestellt haben.</p><p>Überprüfungsmethode:</p><ol><li>Initiieren Sie eine Anforderung, die eine Token-Aktualisierung auslöst (z. B. warten Sie, bis das Token kurz vor dem Ablauf steht, und fordern Sie dann an)</li><li>Beobachten Sie, dass die Protokolle nicht mehr den Hinweis &quot;Überspringen von disabled-Konto&quot; enthalten</li></ol><p><strong>Was Sie sehen sollten</strong>: Die Anforderungen können normal durchlaufen, und in den Protokollen erscheint nicht mehr der <code>invalid_grant</code>-Sperrungsprozess für dieses Konto.</p><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><h3 id="❌-disabled-als-temporare-rotation-behandeln" tabindex="-1">❌ disabled als &quot;temporäre Rotation&quot; behandeln <a class="header-anchor" href="#❌-disabled-als-temporare-rotation-behandeln" aria-label="Permalink to &quot;❌ disabled als &quot;temporäre Rotation&quot; behandeln&quot;">​</a></h3><p>Wenn Sie nur in der Benutzeroberfläche sehen, dass &quot;das Konto noch da ist&quot;, können Sie leicht fälschlicherweise glauben, dass &quot;das System es nur vorübergehend nicht verwendet&quot;. Aber <code>disabled=true</code> wird auf die Festplatte geschrieben und bleibt auch nach dem Neustart wirksam.</p><h3 id="❌-nur-access-token-erganzen-refresh-token-nicht-aktualisieren" tabindex="-1">❌ Nur access_token ergänzen, refresh_token nicht aktualisieren <a class="header-anchor" href="#❌-nur-access-token-erganzen-refresh-token-nicht-aktualisieren" aria-label="Permalink to &quot;❌ Nur access_token ergänzen, refresh_token nicht aktualisieren&quot;">​</a></h3><p>Der Auslösepunkt für <code>invalid_grant</code> ist der <code>refresh_token</code>, der beim Aktualisieren des <code>access_token</code> verwendet wird. Wenn Sie nur temporär ein noch verwendbares <code>access_token</code> erhalten, aber der <code>refresh_token</code> weiterhin ungültig ist, wird die Sperrung erneut ausgelöst.</p><h2 id="kontrollpunkte-✅" tabindex="-1">Kontrollpunkte ✅ <a class="header-anchor" href="#kontrollpunkte-✅" aria-label="Permalink to &quot;Kontrollpunkte ✅&quot;">​</a></h2><ul><li>[ ] Sie können in den Protokollen bestätigen, dass <code>invalid_grant</code> durch das Fehlschlagen der refresh_token-Aktualisierung verursacht wurde</li><li>[ ] Sie kennen den semantischen Unterschied zwischen <code>disabled</code> und <code>proxy_disabled</code></li><li>[ ] Sie können das Konto durch erneutes Hinzufügen des Kontos (OAuth oder refresh_token) wiederherstellen</li><li>[ ] Sie können verifizieren, dass die Wiederherstellung für den laufenden Proxy wirksam ist</li></ul><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><ul><li>Wenn <code>invalid_grant</code> auftritt, markiert der Proxy das Konto <strong>als disabled auf die Festplatte geschrieben</strong> und entfernt es aus dem Token-Pool, um wiederholte Fehlschläge zu vermeiden</li><li>Der Schlüssel zur Wiederherstellung ist &quot;explizites Aktualisieren des Token&quot; (erneutes OAuth oder erneutes Hinzufügen mit einem neuen refresh_token), das System löscht automatisch die <code>disabled_*</code>-Felder</li><li>Die Konto-JSON im Datenverzeichnis ist die maßgebliche Quelle für den Status (Sperrung/Grund/Zeitpunkt sind alle darin enthalten)</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../auth-401/">401/Authentifizierungsfehler: auth_mode, Header-Kompatibilität und Client-Konfigurationsliste</a></strong>.</p><p>Sie lernen:</p><ul><li>401 ist normalerweise ein Problem auf welcher Ebene von &quot;Modus/Key/Header&quot;</li><li>Welcher Authentifizierungs-Header sollte von verschiedenen Clients mitgeführt werden</li><li>Wie man mit dem kürzesten Weg selbst prüft und behebt</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Persistentes Schreiben von <code>disabled/disabled_at/disabled_reason</code> und Entfernen aus dem Arbeitsspeicher</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L942-L969" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>942-969</td></tr><tr><td>Abschneiden von <code>disabled_reason</code> (Vermeiden von Vergrößerung der Kontodatei)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1464-L1471" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1464-1471</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table></details>`,49)])])}const p=n(a,[["render",s]]);export{g as __pageData,p as default};
